function createProfileImage(initials, startColor, endColor, accentColor) {
  const svg = `
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 320 320">
      <defs>
        <linearGradient id="bg" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stop-color="${startColor}" />
          <stop offset="100%" stop-color="${endColor}" />
        </linearGradient>
      </defs>
      <rect width="320" height="320" rx="72" fill="url(#bg)" />
      <circle cx="250" cy="82" r="38" fill="${accentColor}" opacity="0.45" />
      <circle cx="78" cy="248" r="52" fill="#ffffff" opacity="0.16" />
      <text
        x="160"
        y="188"
        text-anchor="middle"
        font-size="110"
        font-family="Arial, Helvetica, sans-serif"
        font-weight="700"
        fill="#fffaf6"
      >
        ${initials}
      </text>
    </svg>
  `;

  return `data:image/svg+xml;charset=UTF-8,${encodeURIComponent(svg)}`;
}

